  SELECT MIN(timestamp) / 3600 FROM events
  UNION ALL
  SELECT h + 1 FROM hours WHERE h < (SELECT MAX(timestamp) / 3600 FROM events)
) SELECT h * 3600 as time, COALESCE(e.cnt, 0) as events FROM hours LEFT JOIN (SELECT timestamp / 3600 as hr, COUNT(*) as cnt FROM events GROUP BY hr) e ON hours.h = e.hr ORDER BY time;

