WITH RECURSIVE hours(h) AS (
  SELECT COALESCE(MIN(timestamp) / 3600, strftime('%s', 'now') / 3600) FROM events
  UNION ALL
  SELECT h + 1 FROM hours WHERE h < (SELECT COALESCE(MAX(timestamp) / 3600, strftime('%s', 'now') / 3600) FROM events)
), narration AS (
  SELECT timestamp / 3600 AS hr, COUNT(*) AS cnt FROM events WHERE event_type='narration_rejection' GROUP BY hr
), claims AS (
  SELECT timestamp / 3600 AS hr, COUNT(*) AS cnt FROM events WHERE event_type IN ('narration_rejection', 'task_completed') GROUP BY hr
) SELECT h * 3600 AS time, CASE WHEN COALESCE(claims.cnt, 0) = 0 THEN 0.0 ELSE CAST(COALESCE(narration.cnt, 0) AS REAL) / claims.cnt END AS narration_rejection_rate FROM hours LEFT JOIN narration ON hours.h = narration.hr LEFT JOIN claims ON hours.h = claims.hr ORDER BY time;

